from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismUsdUpdateDepartmentLayerNode(BaseNode):
    name = "Prism USD: Update Department Layer"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("department_usd_path", "string", widget_type="file")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        path = inputs.get('department_usd_path') or ''
        if core is None or not path:
            self.log_error("Need PrismCore and department_usd_path.")
            return {'success': False}
        try:
            plugin = core.getPlugin('USD') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('USD')
            if plugin is None:
                self.log_error("USD plugin not loaded.")
                return {'success': False}
            plugin.api.updateDepartmentLayerInCurrentEntityUSD(path)
            self.log_success(f"Updated department layer: {path}")
            await self.set_output('exec_out', True)
            return {'success': True}
        except Exception as e:
            self.log_error(f"updateDepartmentLayerInCurrentEntityUSD failed: {e}")
            return {'success': False}

def register_node():
    return PrismUsdUpdateDepartmentLayerNode
